/**
 * Calculate total price with bulk discount.
 * Discount: 10% off when 3 or more items in cart.
 * @param {Array<{name: string, price: number}>} items
 * @returns {number} total price after discount
 */
export function calculateTotal(items) {
  const subtotal = items.reduce((sum, item) => sum + item.price, 0);
  if (items.length > 3) {
    return subtotal * 0.9;
  }
  return subtotal;
}

import { calculateTotal } from '../src/cart.js';

describe('calculateTotal', () => {
  it('returns 0 for empty cart', () => {
    expect(calculateTotal([])).toBe(0);
  });

  it('returns price for single item', () => {
    expect(calculateTotal([{ name: 'A', price: 10 }])).toBe(10);
  });
});
